 function inferNumber(q){const candidates=[q.value,q.number,q.standard_number,q.correct_answer,q.answer,nums(q.prompt)[0]]; for(const c of candidates){const raw=String(c??'').replace(/,/g,''); if(raw!==''&&Number.isFinite(Number(raw)))return Number(raw);} return 0;}
 function numberLine(q){const fraction=fractionParts(q); const isFractionLine=(q.numerator!==undefined||q.denominator!==undefined||q.fraction!==undefined||q.label!==undefined||/(fraction|0 to 1|number line from 0 to 1|\/)/i.test([q.prompt,q.correct_answer,q.answer].join(' ')))&&fraction.denominator>1; if(isFractionLine){return fractionNumberLine(q,fraction);} const n=nums([q.prompt,q.correct_answer,q.min,q.max,q.left,q.right,q.left_value,q.right_value].join(' ')); const answerNums=nums(q.correct_answer); const rawValue=String(q.value??q.number??'').replace(/,/g,''); const rawAnswer=String(q.correct_answer??'').replace(/,/g,''); const center=rawValue!==''&&Number.isFinite(Number(rawValue))?Number(rawValue):(rawAnswer!==''&&Number.isFinite(Number(rawAnswer))?Number(rawAnswer):(answerNums[0]||n[0]||0)); const rawMin=Number.isFinite(Number(q.min))?Number(q.min):Math.max(0,center-3); const inferredMax=Math.max(center+3,...n,rawMin+1); const rawMax=Number.isFinite(Number(q.max))?Number(q.max):inferredMax; const span=Math.max(1,rawMax-rawMin); const large=span>16||Math.max(Math.abs(rawMax),Math.abs(rawMin),Math.abs(center))>1000; let tickValues=[]; if(large){const quarter=span/4; tickValues=[rawMin,rawMin+quarter,center,rawMax-quarter,rawMax].map((v)=>Math.round(v)); tickValues=[...new Set(tickValues.concat([rawMin,rawMax,center]).sort((a,b)=>a-b))];} else {const min=Math.min(Math.max(0,center-4,rawMin),center); const max=Math.max(Math.min(Math.max(120,rawMax,center,...n),center+4,rawMax),center); for(let x=min;x<=max;x++)tickValues.push(x);} const points=tickValues.map((x)=>`<span class="sw-number-point ${x===center?'is-missing':''}"><b>${x===center&&q.hide_value!==false?'?':formatNumberLabel(x)}</b></span>`); const dir=/back|before|subtract|less/i.test(q.prompt||'')?'backward':'forward'; const caption=large?'Use the benchmark labels to locate and compare large Grade 4 values.':'Use each tick to count by one. The highlighted mystery tick is the answer.'; return `<div class="visual-model skill-visual-inner number-line-visual" data-renderer="number_line"><div class="sw-direction ${dir}">${dir==='forward'?'➡️ Forward':'⬅️ Backward'}</div><div class="visual-scroll number-line-window" aria-label="Focused number line from ${formatNumberLabel(rawMin)} to ${formatNumberLabel(rawMax)}"><div class="sw-number-line large-number-line">${points.join('')}</div></div><p class="sw-visual-caption">${caption}</p></div>`;}
 function placeParts(q){const val=inferNumber(q); const places=[['millions',1000000],['hundred_thousands',100000],['ten_thousands',10000],['thousands',1000],['hundreds',100],['tens',10],['ones',1]]; const digits={}; places.forEach(([name,place])=>{digits[name]=Number.isFinite(Number(q[name]))?Number(q[name]):Math.floor(val/place)%10;}); return {val,places,digits,hundreds:digits.hundreds,tens:digits.tens,ones:digits.ones};}
 function placeValueChart(q,renderer='place_value_chart'){const {val,places,digits}=placeParts(q); const active=String(q.place||q.target_place||'').replace(/\s+/g,'_').toLowerCase(); const cells=places.map(([name,place])=>{const d=digits[name]; const label=name.split('_').map((part)=>part.charAt(0).toUpperCase()+part.slice(1)).join(' '); const value=d*place; return `<div class="${active===name?'is-target-place':''}"><h4>${label}</h4><strong>${esc(d)}</strong><small>${formatNumberLabel(value)}</small></div>`;}).join(''); return `<div class="visual-model skill-visual-inner place-value-chart-visual" data-renderer="${esc(renderer)}"><div class="place-value-chart grade4-place-value-chart">${cells}</div><p class="sw-visual-caption">${formatNumberLabel(val)} is organized from millions to ones. Zeros still hold their places.</p></div>`;}
 function expandedForm(q){const {val,places,digits}=placeParts(q); const values=places.map(([name,place])=>({name,place,digit:digits[name],value:digits[name]*place})); const nonzero=values.filter((part)=>part.value>0); const expression=q.expanded_form||q.expanded||nonzero.map((part)=>formatNumberLabel(part.value)).join(' + ')||'0'; const cells=values.map((part)=>`<span class="expanded-part ${part.value?'':'zero-part'}"><b>${esc(part.digit)}</b><small>${formatNumberLabel(part.value)}</small></span>`).join(''); return `<div class="visual-model skill-visual-inner expanded-form-visual" data-renderer="expanded_form"><div class="sentence-strip expanded-expression"><strong>${formatNumberLabel(val)}</strong> = <span class="highlight-word">${esc(expression)}</span></div><div class="expanded-place-row">${cells}</div><p class="sw-visual-caption">Expanded form adds the value of each nonzero digit. Zero placeholders stay visible in the chart.</p></div>`;}
 
 function roundingModel(q){const value=inferNumber(q); const place=Number(q.round_to||q.nearest||(/100,?000/i.test(q.prompt||'')?100000:/10,?000/i.test(q.prompt||'')?10000:/1,?000|thousand/i.test(q.prompt||'')?1000:/100|hundred/i.test(q.prompt||'')?100:10)); const lower=Math.floor(value/place)*place; const upper=lower+place; const midpoint=lower+place/2; const rounded=Number(q.rounded||String(q.correct_answer||q.answer||'').replace(/,/g,'')||(value>=midpoint?upper:lower)); const ticks=[lower,midpoint,upper]; const tickHtml=ticks.map((n)=>`<span class="rounding-tick ${n===midpoint?'midpoint':''} ${n===rounded?'target':''}"><b>${formatNumberLabel(n)}</b><small>${n===midpoint?'midpoint':(n===rounded?'rounded':'')}</small></span>`).join(''); const direction=value>=midpoint?'round up':'round down'; return `<div class="visual-model skill-visual-inner rounding-model-visual" data-renderer="rounding_model"><div class="rounding-range"><span>${formatNumberLabel(lower)}</span><strong>${formatNumberLabel(value)}</strong><span>${formatNumberLabel(upper)}</span></div><div class="sw-number-line rounding-line grade4-rounding-line">${tickHtml}</div><p class="sw-visual-caption">To round ${formatNumberLabel(value)} to the nearest ${formatNumberLabel(place)}, compare it with midpoint ${formatNumberLabel(midpoint)} and ${direction} to ${formatNumberLabel(rounded)}.</p></div>`;}
 function parseFractionValue(value){const text=String(value??'').trim(); const match=text.match(/(\d+)\s*\/\s*(\d+)/); if(match){return {numerator:Number(match[1]),denominator:Number(match[2])};} return null;}
 function firstFractionFrom(q){return [q.fraction,q.label,q.correct_answer,q.answer,q.left,q.right,q.prompt].map(parseFractionValue).find(Boolean)||null;}
 function fractionParts(q){const parsed=firstFractionFrom(q)||{}; const numeratorRaw=q.numerator??q.shaded??q.shaded_parts??q.filled??parsed.numerator??1; const denominatorRaw=q.denominator??q.total_parts??q.parts??q.total??parsed.denominator??2; const numerator=Number(numeratorRaw); const denominator=Number(denominatorRaw); const safeDenominator=Number.isFinite(denominator)&&denominator>0?Math.round(denominator):2; const safeNumerator=Number.isFinite(numerator)?Math.round(numerator):1; return {numerator:Math.max(0,safeNumerator),denominator:safeDenominator};}
 function fractionLabel(parts){return `${parts.numerator}/${parts.denominator}`;}
 function fractionBar(q){const parts=fractionParts(q); const total=Math.max(1,Math.min(parts.denominator,12)); const filled=Math.max(0,Math.min(parts.numerator,total)); const label=fractionLabel(parts); const cells=Array.from({length:total},(_,i)=>`<span class="fraction-bar-cell ${i<filled?'filled':''}" data-part="${i+1}" aria-label="part ${i+1} of ${total}${i<filled?', shaded':''}"></span>`).join(''); return `<div class="visual-model skill-visual-inner fraction-bar-visual" data-renderer="fraction_bar"><div class="fraction-bar-label">${esc(label)}</div><div class="fraction-bar" style="--parts:${total}" aria-label="fraction bar ${esc(label)} with ${filled} of ${total} equal parts shaded">${cells}</div><p class="sw-visual-caption">${esc(label)} means ${esc(parts.numerator)} of ${esc(parts.denominator)} equal parts are shaded.</p></div>`;}
