  comparison:(q)=>{const left=safe(q.left_value,q.left??'?'), right=safe(q.right_value,q.right??'?'); const leftFraction=parseFractionValue(left), rightFraction=parseFractionValue(right); if(leftFraction&&rightFraction){const leftBits=fractionBar({numerator:leftFraction.numerator,denominator:leftFraction.denominator}).replace('skill-visual-inner fraction-bar-visual','fraction-mini').replace(' data-renderer="fraction_bar"',''); const rightBits=fractionBar({numerator:rightFraction.numerator,denominator:rightFraction.denominator}).replace('skill-visual-inner fraction-bar-visual','fraction-mini').replace(' data-renderer="fraction_bar"',''); return `<div class="visual-model skill-visual-inner comparison-visual fraction-comparison-visual" data-renderer="comparison"><div class="compare-card">${leftBits}</div><strong class="compare-symbol">&gt; &lt; =</strong><div class="compare-card">${rightBits}</div><p class="sw-visual-caption">Compare the shaded parts using the fraction models.</p></div>`;} const leftBits=q.left_items?objectTokens(q.left_items):`<strong>${esc(left)}</strong>`; const rightBits=q.right_items?objectTokens(q.right_items):`<strong>${esc(right)}</strong>`; return `<div class="visual-model skill-visual-inner comparison-visual" data-renderer="comparison"><div class="compare-card">${leftBits}</div><strong class="compare-symbol">&gt; &lt; =</strong><div class="compare-card">${rightBits}</div><p class="sw-visual-caption">Compare hundreds, then tens, then ones.</p></div>`;},
  comparison_cards:(q)=>numberLine(q), number_line_0_120:(q)=>numberLine(q),
