  number_line:numberLine, base_ten_blocks:baseTen, place_value_chart:placeValueChart, expanded_form:expandedForm, rounding_model:roundingModel, fraction_bar:fractionBar, fraction_circle:fractionCircle,
  addition_model:(q)=>`<div class="visual-model skill-visual-inner addition-visual" data-renderer="addition_model"><div>${objectTokens(null,q.a)}</div><b>+</b><div>${objectTokens(null,q.b)}</div><b>=</b><div class="whole-box">whole</div></div>`,
